import{j as t,p as r}from"./index-YFZcxO2M.js";import{P as n}from"./PageHero-Bdeq7tXm.js";const e="#c8161d",l=[{title:"1. قبول الشروط",content:"باستخدامك لمنصة EgyEstate، فإنك توافق على الالتزام بهذه الشروط والأحكام. إذا كنت لا توافق على أي جزء من هذه الشروط، يُرجى عدم استخدام المنصة. نحتفظ بالحق في تعديل هذه الشروط في أي وقت، وسيتم إخطارك بأي تغييرات جوهرية عبر البريد الإلكتروني أو الإشعارات داخل التطبيق."},{title:"2. وصف الخدمة",content:"EgyEstate هي منصة SaaS (برمجيات كخدمة) متخصصة في إدارة الشركات العقارية. تشمل الخدمات: إدارة المشاريع والوحدات العقارية، إدارة العقود والأقساط، نظام المحاسبة، إدارة العملاء، وأدوات التقارير والتحليلات. تقدم المنصة خدماتها عبر الإنترنت فقط وتتطلب اتصالاً فعّالاً."},{title:"3. حسابات المستخدمين",content:"أنت مسؤول عن الحفاظ على سرية بيانات تسجيل الدخول الخاصة بك. يجب إخطارنا فوراً عند الاشتباه في أي وصول غير مصرح به لحسابك. لا نتحمل المسؤولية عن أي خسائر ناجمة عن إخفاقك في حماية بيانات حسابك. يُمنع مشاركة بيانات الدخول مع أطراف غير مصرح لها."},{title:"4. الاشتراك والدفع",content:"تُحسب رسوم الاشتراك شهرياً أو سنوياً وفقاً للخطة المختارة. يُجدَّد الاشتراك تلقائياً ما لم يُلغَ قبل 24 ساعة من تاريخ التجديد. جميع الأسعار بالجنيه المصري وتشمل ضريبة القيمة المضافة. لا يحق المطالبة باسترداد الرسوم المدفوعة عن الفترات المنتهية."},{title:"5. الملكية الفكرية",content:"جميع المحتويات والتصاميم والكود المصدري والشعارات الخاصة بـ EgyEstate هي ملك حصري للشركة ومحمية بموجب قوانين حقوق الملكية الفكرية المصرية والدولية. يُمنع نسخ أو توزيع أو تعديل أي جزء من المنصة دون إذن كتابي مسبق. بياناتك تظل ملكاً لك في جميع الأوقات."},{title:"6. الخصوصية وحماية البيانات",content:"نلتزم بحماية بياناتك الشخصية وبيانات شركتك وفقاً لسياسة الخصوصية المفصّلة. لن نبيع أو نشارك بياناتك مع أطراف ثالثة لأغراض تسويقية. نستخدم تشفير SSL/TLS لحماية البيانات أثناء النقل، ونتخذ إجراءات أمنية صارمة لحماية البيانات المخزنة."},{title:"7. حدود المسؤولية",content:"لا تتحمل EgyEstate مسؤولية أي خسائر غير مباشرة أو عرضية أو تبعية ناجمة عن استخدام المنصة. مسؤوليتنا القصوى في جميع الحالات تقتصر على مبلغ الاشتراك المدفوع في آخر 3 أشهر. لا نضمن استمرارية الخدمة دون انقطاع أو خلو من الأخطاء."},{title:"8. إنهاء الاشتراك",content:"يحق لك إلغاء اشتراكك في أي وقت من لوحة الإعدادات. عند الإلغاء، يمكنك الاحتفاظ بحق الوصول حتى نهاية فترة الاشتراك المدفوعة. بعد انتهاء الاشتراك، سيتم تجميد الحساب لمدة 30 يوماً يمكنك خلالها تصدير بياناتك. نحتفظ بحق تعليق أو إنهاء الحسابات المخالفة لهذه الشروط."},{title:"9. القانون الحاكم",content:"تخضع هذه الشروط وتُفسَّر وفقاً لقوانين جمهورية مصر العربية. أي نزاع ينشأ عن هذه الشروط أو يتعلق بها يُحال أولاً إلى التسوية الودية، وفي حالة تعذّرها، تختص المحاكم المصرية المختصة بالفصل فيه."}];function i(){return t.jsxs(r,{children:[t.jsx(n,{tag:"قانوني",title:"شروط الاستخدام",subtitle:"يُرجى قراءة هذه الشروط بعناية قبل استخدام منصة EgyEstate.",breadcrumb:[{label:"شروط الاستخدام"}]}),t.jsx("div",{}),t.jsxs("div",{className:"max-w-5xl mx-auto px-5 py-12",children:[t.jsx("div",{className:"bg-white rounded-3xl border border-gray-100 shadow-sm p-8 md:p-12 space-y-10",children:l.map((s,a)=>t.jsxs("div",{children:[t.jsx("h2",{className:"text-xl font-black mb-3",style:{color:e},children:s.title}),t.jsx("p",{className:"text-gray-600 leading-[2] text-base",children:s.content}),a<l.length-1&&t.jsx("div",{className:"mt-10 border-b border-gray-50"})]},a))}),t.jsx("div",{className:"mt-8 p-6 rounded-2xl border text-center",style:{background:`${e}08`,borderColor:`${e}20`},children:t.jsxs("p",{className:"text-sm text-gray-600",children:["لأي استفسارات بخصوص شروط الاستخدام، تواصل معنا على"," ",t.jsx("a",{href:"mailto:legal@egyestate.com",className:"font-bold underline",style:{color:e},children:"legal@egyestate.com"})]})})]})]})}export{i as default};
